import React from 'react';
import { StyledPage } from './styles';
import Header from '../Header';
import Footer from '../Footer';
import Layout from '../Layout';

interface PageProps {
    children?: React.ReactNode
}

const Page: React.FC<PageProps> = ({ children }) =>
<StyledPage>
    <Layout></Layout>
    <Header/>
      {children}
    <Footer/>
</StyledPage>;

export default Page;
